-- ── EXTENSIONS ────────────────────────────────────────────────
create extension if not exists "pgcrypto";

-- ── ENUMS ─────────────────────────────────────────────────────
do $$ begin
  create type user_role as enum (
    'super_admin','admin','resp_commercial','team_leader',
    'prevendeur','resp_logistique','magasinier','dispatcheur','livreur',
    'acheteur','ctrl_achat','ctrl_prep',
    'cash_man','financier','rh_manager','comptable',
    'client','fournisseur'
  );
exception when duplicate_object then null; end $$;

do $$ begin
  create type access_type as enum ('mobile','backoffice','both');
exception when duplicate_object then null; end $$;

do $$ begin
  create type classification_rh as enum ('salarie','actionnaire','both');
exception when duplicate_object then null; end $$;

do $$ begin
  create type hr_doc_type as enum ('contrat','fiche_paie','attestation','conge','avertissement');
exception when duplicate_object then null; end $$;

do $$ begin
  create type order_status as enum (
    'brouillon','confirme','en_preparation','pret','en_livraison',
    'livre','retour_partiel','retour_total','annule'
  );
exception when duplicate_object then null; end $$;

-- ── TABLE: depots ──────────────────────────────────────────────
create table if not exists depots (
  id              uuid primary key default gen_random_uuid(),
  nom             text not null,
  ville           text,
  adresse         text,
  responsable_nom text,
  actif           boolean not null default true,
  created_at      timestamptz not null default now()
);

-- ── TABLE: users ──────────────────────────────────────────────
-- Maps 1:1 to Supabase Auth (auth.users). id = auth.users.id
create table if not exists users (
  id              uuid primary key references auth.users(id) on delete cascade,
  name            text not null,
  email           text not null unique,
  role            user_role not null default 'prevendeur',
  access_type     access_type,
  secteur         text,
  phone           text,
  telephone       text,           -- WhatsApp intl format ex: 212661234567
  actif           boolean not null default true,
  photo_url       text,
  depot_id        uuid references depots(id) on delete set null,

  -- HR Classification (OURAI)
  classification  classification_rh,
  matricule       text unique,    -- Auto-generated: FL-YYYYROLE-NNN
  date_embauche   date,
  salaire_base    numeric(10,2),

  -- Permissions
  can_view_achat          boolean not null default false,
  can_view_commercial     boolean not null default false,
  can_view_logistique     boolean not null default false,
  can_view_stock          boolean not null default false,
  can_view_cash           boolean not null default false,
  can_view_finance        boolean not null default false,
  can_view_recap          boolean not null default false,
  can_view_database       boolean not null default false,
  can_view_rh             boolean not null default false,
  can_view_external       boolean not null default false,
  can_create_commande_bo  boolean not null default false,

  -- Objectifs prévendeur
  objectif_clients            int default 0,
  objectif_tonnage            int default 0,
  objectif_journalier_ca      numeric(10,2) default 0,
  objectif_hebdomadaire_ca    numeric(10,2) default 0,
  objectif_mensuel_ca         numeric(10,2) default 0,
  objectif_journalier_clients int default 0,
  objectif_hebdomadaire_clients int default 0,
  objectif_mensuel_clients    int default 0,

  -- Security
  require_camera_auth boolean default false,
  password_mobile     text,
  password_bo         text,

  -- Portal linking
  fournisseur_id  uuid,
  client_id       uuid,

  created_at      timestamptz not null default now(),
  updated_at      timestamptz not null default now()
);

-- Auto-update updated_at
create or replace function set_updated_at()
returns trigger language plpgsql as $$
begin new.updated_at = now(); return new; end $$;

drop trigger if exists users_updated_at on users;
create trigger users_updated_at
  before update on users
  for each row execute function set_updated_at();

-- Auto-generate matricule when classification = 'salarie' or 'both'
create or replace function generate_matricule()
returns trigger language plpgsql as $$
declare
  role_code text;
  year_code text;
  seq_num   int;
  new_mat   text;
begin
  if new.matricule is null and new.classification in ('salarie','both') then
    role_code := case new.role
      when 'prevendeur'      then 'PRV'
      when 'livreur'         then 'LIV'
      when 'magasinier'      then 'MAG'
      when 'acheteur'        then 'ACH'
      when 'resp_logistique' then 'LOG'
      when 'resp_commercial' then 'COM'
      when 'dispatcheur'     then 'DIS'
      when 'cash_man'        then 'CSH'
      when 'financier'       then 'FIN'
      when 'rh_manager'      then 'RHM'
      when 'comptable'       then 'CPT'
      when 'admin'           then 'ADM'
      when 'super_admin'     then 'SPA'
      else 'EMP'
    end;
    year_code := to_char(now(), 'YYYY');
    select coalesce(max(cast(right(matricule,3) as int)),0) + 1
      into seq_num
      from users
      where matricule like 'FL-' || year_code || role_code || '-%';
    new_mat := 'FL-' || year_code || role_code || '-' || lpad(seq_num::text, 3, '0');
    new.matricule := new_mat;
  end if;
  return new;
end $$;

drop trigger if exists users_matricule on users;
create trigger users_matricule
  before insert on users
  for each row execute function generate_matricule();

-- ── TABLE: products / catalogue ───────────────────────────────
create table if not exists products (
  id              uuid primary key default gen_random_uuid(),
  sku             text not null unique,
  name            text not null,
  name_ar         text,
  category        text,           -- fruits, legumes, herbes, surgeles...
  unit            text not null default 'kg',  -- kg, piece, caisse, palette
  price_achat     numeric(10,2),
  price_vente     numeric(10,2),
  prix_plancher   numeric(10,2),  -- prix min vente (Jawad)
  stock_actuel    numeric(10,3) default 0,
  stock_securite  numeric(10,3) default 0,
  actif           boolean not null default true,
  image_url       text,
  depot_id        uuid references depots(id) on delete set null,
  created_at      timestamptz not null default now(),
  updated_at      timestamptz not null default now()
);

drop trigger if exists products_updated_at on products;
create trigger products_updated_at
  before update on products
  for each row execute function set_updated_at();

