-- ── TABLE: prix_historique_fournisseur ────────────────────────
-- Historique prix par SKU/fournisseur — used by ASHEL & Simohammed
create table if not exists prix_historique_fournisseur (
  id              uuid primary key default gen_random_uuid(),
  fournisseur_id  uuid not null references fournisseurs(id) on delete cascade,
  product_id      uuid not null references products(id) on delete cascade,
  prix_achat      numeric(10,2) not null,
  quantite_kg     numeric(10,3),
  score_qualite   int,            -- 1-10 at time of purchase
  date_achat      date not null default current_date,
  acheteur_id     uuid references users(id) on delete set null,
  notes           text,
  created_at      timestamptz not null default now()
);

create index if not exists idx_prix_historique_fournisseur_product
  on prix_historique_fournisseur(product_id, date_achat desc);

-- ── TABLE: orders (commandes) ─────────────────────────────────
create table if not exists orders (
  id              uuid primary key default gen_random_uuid(),
  reference       text unique,    -- CMD-YYYYMMDD-NNN
  client_id       uuid references clients(id) on delete set null,
  prevendeur_id   uuid references users(id) on delete set null,
  livreur_id      uuid references users(id) on delete set null,
  depot_id        uuid references depots(id) on delete set null,
  status          order_status not null default 'brouillon',
  date_commande   timestamptz not null default now(),
  date_livraison  date,
  montant_total   numeric(10,2) default 0,
  montant_paye    numeric(10,2) default 0,
  modalite_paiement text default 'cash',
  notes           text,
  created_at      timestamptz not null default now(),
  updated_at      timestamptz not null default now()
);

drop trigger if exists orders_updated_at on orders;
create trigger orders_updated_at
  before update on orders
  for each row execute function set_updated_at();

-- ── TABLE: order_lines ────────────────────────────────────────
create table if not exists order_lines (
  id              uuid primary key default gen_random_uuid(),
  order_id        uuid not null references orders(id) on delete cascade,
  product_id      uuid not null references products(id) on delete restrict,
  quantite        numeric(10,3) not null,
  prix_unitaire   numeric(10,2) not null,
  remise_pct      numeric(5,2) default 0,
  montant_ligne   numeric(10,2) generated always as (quantite * prix_unitaire * (1 - remise_pct/100)) stored,
  notes           text
);

