  type            hr_doc_type not null,
  titre           text not null,
  contenu_json    jsonb,          -- structured content (salaire, primes, retenues...)
  pdf_url         text,           -- stored in Supabase Storage
  periode_mois    int,            -- 1-12
  periode_annee   int,
  salaire_brut    numeric(10,2),
  cnss_salarie    numeric(10,2),
  amo             numeric(10,2),
  ir              numeric(10,2),
