create index if not exists idx_hr_docs_user_periode
  on hr_docs(user_id, periode_annee desc, periode_mois desc);

-- ── TABLE: logistics_trips ────────────────────────────────────
-- Tournées livreurs — used by Jawad for route optimization
create table if not exists logistics_trips (
  id              uuid primary key default gen_random_uuid(),
  livreur_id      uuid references users(id) on delete set null,
  depot_id        uuid references depots(id) on delete set null,
  date_tournee    date not null default current_date,
  km_parcourus    numeric(8,2),
  nb_bl_affectes  int default 0,
  nb_bl_livres    int default 0,
  taux_service    numeric(5,2) generated always as (
    case when nb_bl_affectes > 0 then (nb_bl_livres::numeric / nb_bl_affectes) * 100 else 0 end
  ) stored,
  statut          text default 'planifie',  -- planifie, en_cours, termine
  notes           text,
  created_at      timestamptz not null default now()
);

-- ── TABLE: ai_sessions ────────────────────────────────────────
-- Log des conversations agents IA (audit & apprentissage)
create table if not exists ai_sessions (
  id              uuid primary key default gen_random_uuid(),
  user_id         uuid references users(id) on delete set null,
  agent_id        text not null,  -- jawad, zizi, ourai, ashel, mustapha, simohammed...
  messages        jsonb not null default '[]',
  tokens_used     int,
  duration_ms     int,
  created_at      timestamptz not null default now()
);

-- ── ROW LEVEL SECURITY ────────────────────────────────────────
alter table users enable row level security;
alter table products enable row level security;
alter table clients enable row level security;
alter table fournisseurs enable row level security;
alter table orders enable row level security;
alter table order_lines enable row level security;
alter table hr_docs enable row level security;
alter table depots enable row level security;

-- Users: each user can read their own row + admins can read all
create policy "users_select_own" on users
  for select using (auth.uid() = id);

create policy "users_select_admin" on users
  for select using (
    exists (
      select 1 from users u
      where u.id = auth.uid()
        and u.role in ('super_admin','admin')
    )
  );

create policy "users_insert_admin" on users
  for insert with check (
    exists (
      select 1 from users u
      where u.id = auth.uid()
        and u.role in ('super_admin','admin')
    )
  );

create policy "users_update_admin" on users
  for update using (
    exists (
      select 1 from users u
      where u.id = auth.uid()
        and u.role in ('super_admin','admin')
    )
  );

-- Products: authenticated users can read; admins can write
create policy "products_select_auth" on products
  for select using (auth.uid() is not null);

create policy "products_write_admin" on products
  for all using (
    exists (
      select 1 from users u
      where u.id = auth.uid()
        and u.role in ('super_admin','admin','acheteur','ctrl_achat')
    )
  );

-- HR docs: only the user + rh_manager/admin
create policy "hr_docs_select" on hr_docs
  for select using (
    user_id = auth.uid()
    or exists (
      select 1 from users u
      where u.id = auth.uid()
        and u.role in ('super_admin','admin','rh_manager','comptable')
    )
  );

-- ── INDEXES ───────────────────────────────────────────────────
create index if not exists idx_users_role on users(role);
create index if not exists idx_users_depot on users(depot_id);
create index if not exists idx_orders_client on orders(client_id);
create index if not exists idx_orders_status on orders(status);
create index if not exists idx_orders_date on orders(date_commande desc);
create index if not exists idx_order_lines_order on order_lines(order_id);
create index if not exists idx_clients_prevendeur on clients(prevendeur_id);
create index if not exists idx_logistics_livreur on logistics_trips(livreur_id, date_tournee desc);

